INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'mt', 24, 1, NULL, 'Thomas Watson em Mt 24:1', 'Thomas Watson destaca a piedade prática e a santificação do coração. Em Mateus 24, o foco recai sobre a pessoa e a obra redentora de Cristo e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Thomas Watson', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'mt', 25, 1, NULL, 'Andrew Murray em Mt 25:1', 'Andrew Murray interpreta este versículo a partir de a coerência doutrinária aplicada à vida cristã. Em Mateus 25, Deus revela a pessoa e a obra redentora de Cristo de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Andrew Murray', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'mt', 26, 1, NULL, 'Orígenes em Mt 26:1', 'Segundo Orígenes, a leitura cristológica e eclesial da passagem ilumina o sentido deste texto. Mateus 26 mostra que a pessoa e a obra redentora de Cristo sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Orígenes', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'mt', 27, 1, NULL, 'Richard Baxter em Mt 27:1', 'Na leitura de Richard Baxter, vemos a piedade prática e a santificação do coração. Mateus 27 evidencia a pessoa e a obra redentora de Cristo como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Richard Baxter', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'mt', 28, 1, NULL, 'Charles Spurgeon em Mt 28:1', 'Segundo Charles Spurgeon, a coerência doutrinária aplicada à vida cristã ilumina o sentido deste texto. Mateus 28 mostra que a pessoa e a obra redentora de Cristo sustenta a caminhada da fé, especialmente em adoração reverente. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Charles Spurgeon', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'mc', 1, 1, NULL, 'Theodore Beza em Mc 1:1', 'Theodore Beza interpreta este versículo a partir de a centralidade das Escrituras e da graça soberana. Em Marcos 1, Deus revela a pessoa e a obra redentora de Cristo de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Theodore Beza', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'mc', 2, 1, NULL, 'R. A. Torrey em Mc 2:1', 'R. A. Torrey destaca o chamado ao arrependimento, fé viva e missão. Em Marcos 2, o foco recai sobre a pessoa e a obra redentora de Cristo e chama a igreja para santidade prática. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'R. A. Torrey', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'mc', 3, 1, NULL, 'Octavius Winslow em Mc 3:1', 'Octavius Winslow interpreta este versículo a partir de a exposição textual com aplicação pastoral objetiva. Em Marcos 3, Deus revela a pessoa e a obra redentora de Cristo de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Octavius Winslow', 'commentary', '#B45309', NOW()),
